// node_conv_226 -- pointwise (1x1) conv2d, tiled-streaming contract.
//   IC=512, OC=128, IH=IW=28, OH=OW=28, stride=1, padding=0.
//   channel_tile=32 -> IN_BEATS=16, OUT_BEATS=4 per pixel.
//   MP=4, OC_PASSES=32.
// Latency: IN_BEATS + OC_PASSES * (MP*K_TOTAL + 6) = 16 + 32*2054 = 65744.
module node_conv_226 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    localparam IC           = 512;
    localparam OC           = 128;
    localparam OH           = 28;
    localparam OW           = 28;
    localparam K_TOTAL      = 512;
    localparam MP           = 4;
    localparam OC_PASSES    = 32;
    localparam CHANNEL_TILE = 32;
    localparam IN_BEATS     = 16;
    localparam OUT_BEATS    = 4;
    localparam TILE_BITS    = 256;
    localparam PIX_COUNT    = OH * OW;
    localparam integer SCALE_MULT  = 9689;
    localparam integer SCALE_SHIFT = 20;
    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = 26;
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = 34;
    localparam integer SCALE_CONST_W = 15;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF = {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 = SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};
    (* rom_style = "block", ram_style = "block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases  [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_226_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_226_bias.hex",    biases);
    end
    reg signed [7:0] in_latch [0:IC-1];
    localparam ST_LOAD=3'd0, ST_RUNNING=3'd1, ST_BIAS=3'd2, ST_SCALE=3'd3, ST_OUTPUT=3'd4, ST_EMIT=3'd5;
    reg [2:0] state;
    reg [4:0]  in_beat_idx;
    reg [2:0]  out_beat_idx;
    reg [10:0] active_emit_count;
    reg [5:0]  oc_group;
    reg [2:0]  lane_counter;
    reg [9:0]  k_counter;
    reg        mac_done_issuing;
    reg [1:0]  drain_counter;
    reg [OC*8-1:0] out_pack;
    reg signed [7:0]            weight_q;
    reg signed [7:0]            in_byte_q1;
    reg                         mac_valid_q1, mac_valid_q2;
    reg [1:0]                   lane_q1, lane_q2;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;
    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;
    integer i, lane, global_oc;
    wire [16:0] weight_addr_comb;
    assign weight_addr_comb = (oc_group * MP + lane_counter) * K_TOTAL + k_counter;
    integer si;
    always @(posedge clk) begin
        if (state == ST_LOAD && ready_in && valid_in) begin
            for (si = 0; si < CHANNEL_TILE; si = si + 1) in_latch[in_beat_idx * CHANNEL_TILE + si] <= data_in[si*8 +: 8];
        end
        weight_q   <= weights[weight_addr_comb];
        in_byte_q1 <= in_latch[k_counter];
        if ((state == ST_LOAD && ready_in && valid_in && in_beat_idx == IN_BEATS - 1) || (state == ST_OUTPUT && oc_group != OC_PASSES - 1)) begin
            for (si = 0; si < MP; si = si + 1) acc[si] <= {ACC_W{1'b0}};
        end else if (mac_valid_q2) begin
            acc[lane_q2] <= acc[lane_q2] + $signed({{(ACC_W-PROD_W){mul_q[PROD_W-1]}}, mul_q});
        end
        if (state == ST_BIAS) for (si = 0; si < MP; si = si + 1) biased[si] <= $signed(acc[si]) + $signed(biases[oc_group * MP + si]);
        if (state == ST_SCALE) for (si = 0; si < MP; si = si + 1) scaled[si] <= $signed(biased[si]) * $signed(SCALE_MULT_CONST);
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= ST_LOAD; ready_in <= 1'b1; valid_out <= 1'b0; data_out <= 256'b0;
            in_beat_idx <= 0; out_beat_idx <= 0; active_emit_count <= 0; oc_group <= 0;
            lane_counter <= 0; k_counter <= 0; mac_done_issuing <= 0; drain_counter <= 0;
            mac_valid_q1 <= 0; mac_valid_q2 <= 0; lane_q1 <= 0; lane_q2 <= 0;
            mul_q <= 0; out_pack <= 0; v_tmp <= 0;
        end else begin
            mac_valid_q1 <= (state == ST_RUNNING) && !mac_done_issuing;
            lane_q1 <= lane_counter[1:0];
            mac_valid_q2 <= mac_valid_q1;
            lane_q2 <= lane_q1;
            mul_q <= weight_q * in_byte_q1;
            case (state)
                ST_LOAD: begin
                    ready_in <= 1'b1; valid_out <= 1'b0;
                    if (valid_in) begin
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx <= 0; ready_in <= 1'b0; state <= ST_RUNNING;
                            oc_group <= 0; lane_counter <= 0; k_counter <= 0;
                            mac_done_issuing <= 0; drain_counter <= 0;
                        end else in_beat_idx <= in_beat_idx + 1;
                    end
                end
                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        if (k_counter == K_TOTAL - 1) begin
                            k_counter <= 0;
                            if (lane_counter == MP - 1) begin lane_counter <= 0; mac_done_issuing <= 1; end
                            else lane_counter <= lane_counter + 1;
                        end else k_counter <= k_counter + 1;
                    end else begin
                        if (drain_counter == 2) begin state <= ST_BIAS; drain_counter <= 0; end
                        else drain_counter <= drain_counter + 1;
                    end
                end
                ST_BIAS: state <= ST_SCALE;
                ST_SCALE: state <= ST_OUTPUT;
                ST_OUTPUT: begin
                    for (lane = 0; lane < MP; lane = lane + 1) begin
                        global_oc = oc_group * MP + lane;
                        v_tmp = (scaled[lane] + (scaled[lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                        out_pack[global_oc*8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    end
                    if (oc_group == OC_PASSES - 1) begin
                        valid_out <= 1'b1; data_out <= out_pack[0 +: TILE_BITS]; out_beat_idx <= 1; state <= ST_EMIT;
                    end else begin
                        oc_group <= oc_group + 1; k_counter <= 0; lane_counter <= 0;
                        mac_done_issuing <= 0; drain_counter <= 0; state <= ST_RUNNING;
                    end
                end
                ST_EMIT: begin
                    if (out_beat_idx == OUT_BEATS) begin
                        valid_out <= 1'b0; ready_in <= 1'b1; out_beat_idx <= 0; state <= ST_LOAD;
                        if (active_emit_count == PIX_COUNT - 1) active_emit_count <= 0;
                        else active_emit_count <= active_emit_count + 1;
                    end else begin
                        data_out <= out_pack[out_beat_idx * TILE_BITS +: TILE_BITS];
                        valid_out <= 1'b1; out_beat_idx <= out_beat_idx + 1;
                    end
                end
                default: state <= ST_LOAD;
            endcase
        end
    end
endmodule
